// Node.js Express middleware (illustrative)
const redis = require('redis');
const db = require('./db'); // simplified DB client
const client = redis.createClient();

async function idempotencyMiddleware(req, res, next) {
  const key = req.get('Idempotency-Key');
  if (!key) return next();

  const cacheKey = `idem:${req.user.accountId}:${key}`;
  const cached = await client.getAsync(cacheKey);
  if (cached) {
    const parsed = JSON.parse(cached);
    return res.status(parsed.status).json(parsed.body);
  }

  // Reserve the key (placeholder) to prevent races
  await client.setAsync(cacheKey, JSON.stringify({status: 202, body: {message: 'processing'}}), 'PX', 60 * 1000);

  // persist an intent in the account shard
  await db.insertIntent({accountId: req.user.accountId, idemKey: key, payload: req.body});

  // attach cacheKey for handler to write final response
  res.locals.idemCacheKey = cacheKey;
  next();
}

