async function runOrderSaga(order, store) {
  const saga = await store.create({ orderId: order.id, step: 'START', steps: {} })
  try {
    await paymentService.charge(order.payment)
    await store.update(saga.id, { 'steps.payment': 'done' })

    await inventoryService.reserve(order.items)
    await store.update(saga.id, { 'steps.inventory': 'done' })

    await shippingService.createShipment(order)
    await store.update(saga.id, { 'steps.shipping': 'done', status: 'completed' })

    return { ok: true }
  } catch (err) {
    // Compensate in reverse order based on persisted step state
    const s = await store.get(saga.id)
    if (s.steps.shipping === 'done') await shippingService.cancel(order)
    if (s.steps.inventory === 'done') await inventoryService.release(order.items)
    if (s.steps.payment === 'done') await paymentService.refund(order.payment)

    await store.update(saga.id, { status: 'failed', error: err.message })
    return { ok: false, error: err.message }
  }
}
